Here is an example of a PRNG using the Nodes system:
```
import { nodeObject, float, uint, add, mul, shiftRight, bitXor, makeFloat } from 'nodes/ShaderNode.js';
import VarNode from 'nodes/core/VarNode.js';

const ONE_OVER_POW = float( 1 / 2 ** 32 );

const u1 = uint( 1 );
const u4 = uint( 4 );
const u22 = uint( 22 );
const u28 = uint( 28 );
const u27e = uint( 277803737 );
const u28e = uint( 2891336453 );
const u74e = uint( 747796405 );

function makeVarNode( node ) {
	if ( node.node ) // node is a VarNode
		return node;
	return nodeObject( new VarNode( node ) );
}

const seed = makeVarNode( uint( 1234 ) );

function hash( num ) { // taken from pcg-random.org
	const state = makeVarNode( add( mul( num, u74e ), u28e ) );
	const word = makeVarNode( mul( bitXor( shiftRight( state, add( shiftRight( state, u28 ), u4 ) ), state ), u27e ) );
	return makeVarNode( makeFloat( bitXor( shiftRight( word, u22 ), word ) ) );
}

function getNextHash() {
	return hash( makeVarNode( assign( seed, add( seed, u1 ) ) ) );
}

function random() { // returns a value between 0 (inclusive) and 1 (exclusive)
	return makeVarNode( mul( getNextHash(), ONE_OVER_POW ) );
}
```

