https://gist.github.com/tommyettinger/46a874533244883189143505d203312c

```javascript
function mulberry32(a) {
    return function() {
      var t = a += 0x6D2B79F5;
      t = Math.imul(t ^ t >>> 15, t | 1);
      t ^= t + Math.imul(t ^ t >>> 7, t | 61);
      return ((t ^ t >>> 14) >>> 0) / 4294967296;
    }
}

var seed = 1;
var prng = mulberry32( seed );
console.log(prng()); // 0.6270739405881613
console.log(prng()); // 0.002735721180215478
```

As you can see it works a bit differently than the current MathUtils.seededRandom function, since providing a seed here actually returns a function, instead of a number. 
