          throw new Error(`t (= ${t}) is not between 0 and 1 inclusive.`)
      } else if (t === 1) {
          return this.curves[this.curves.length - 1].getPoint(1, optionalTarget)
      }
      // If t in [0,1)
      const sectionFractionalIndex = t * this.curves.length
