```JavaScript
function get_axes( order ){
    if (!(typeof order === 'string' || order instanceof String)){
        throw new Error( 'Order must be a string.' );
    }

    if (order.length != 3){
        throw new Error( 'Order must have a length of 3.' );
    }

    if (order != order.toUpperCase()){
        throw new Error( 'Order must be an uppercase string.' );
    }

    if (i == j || j == k){
        throw new Error( 'Consecutive axes must be different.' );
    }

    i = order.charCodeAt(0) - 'X'.charCodeAt(0);
    j = order.charCodeAt(1) - 'X'.charCodeAt(0);
    k = order.charCodeAt(2) - 'X'.charCodeAt(0);

    // check if sequence are equivalent to Proper Euler angles
    symmetric = i == k; 
    if (symmetric) {
        k = 3 - i - j;
    }

    parity = (k - j) * (j - i) * (i - k) / 2;

    return [i, j, k, parity, symmetric];
}
```

And then, the implementation of the Quaternion to Euler conversion is probably something like this (if my JavaScript knowledge is correct), to be put into `Euler.js`:
```JavaScript
        // Based on: Bernardes E, Viollet S (2022) Quaternion to Euler angles conversion: 
	// A direct, general and computationally efficient method. PLoS ONE 17(11): e0276302.
	setFromQuaternion( q, order, update ){

		axes = MathUtils.get_axes( order );
		i = axes[0];
		j = axes[1];
		k = axes[2];
		parity = axes[3];
		symmetric = axes[4];

		v = [q.x, q.y, q.z]
		if (symmetric) {
			a = q.w;
			b = v[i];
			c = v[j];
			d = v[k] * parity;
		} else {
			a = q.w - v[j];
			b = v[i] + v[k] * parity;
			c = v[j] + q.w;
			d = v[k] * parity - v[i];
		}

		angles = [0, 0, 0];

		// middle angle is always easy
		angles[1] = Math.atan2(Math.hypot(c, d), Math.hypot(a, b));

		half_sum = Math.atan2(b, a);
		half_diff = Math.atan2(d, c);

		// check if the case is degenerate
		eps = 10E-7
		if (Math.abs(angles[1]) < eps){
			unsafe = 1;
		} else if (Math.abs(angles[1] - Math.PI) < eps){
			unsafe = 2;
		} else {
			unsafe = 0;
		}

		if (unsafe == 0) {
			angles[2] = half_sum - half_diff
			angles[0] = half_sum + half_diff
		} else { // degenerate cases
			angles[2] = 0;
			if (unsafe == 1) {
				angles[0] = 2 * half_sum;
			} else {
				angles[0] = 2 * half_diff;
			}
		}

		if (!symmetric){
			angles[0] *= parity;
			angles[1] -= Math.PI / 2;
		}

		for (let i = 0; i < 3; i++) {
			if (angles[i] < -Math.PI) {
				angles[i] += 2 * Math.PI;
			} else if (angles[i] > Math.PI) {
				angles[i] -= 2 * Math.PI;
			}
		} 

		this._x = angles[0];
		this._y = angles[1];
		this._z = angles[2];
	}
