        libInstances.url = {};
        libInstances.url.attributes = {};
        libInstances.url.attributes.maxInstanceNum = instances;

        initIBuffGeofromGeoBuff(object.children[0].geometry,libInstances.url);
       
        const shader_basic = {};
        // unifrom values for basic shader
        shader_basic.uniforms = {
            diffuse: { value: new THREE.Color(0xffffff) },
           /*  pMax : ,
